from typing import List
from functools import lru_cache

class Solution:
    def maximumLength(self, nums: List[int], k: int) -> int:
        n = len(nums)

        @lru_cache(maxsize=None)
        def dp(i, last_val, mismatches):
            if i == n:
                return 0
            # Option 1: skip current element
            skip = dp(i + 1, last_val, mismatches)
            # Option 2: take current element
            new_mismatches = mismatches + (0 if nums[i] == last_val else 1)
            take = 1 + dp(i + 1, nums[i], new_mismatches) if new_mismatches <= k else -1
            return max(skip, take)

        return dp(0, -1, 0)
